import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

import { useCallback, useEffect, useState } from "react";

const STORAGE_KEY = "reduce-motion";

function getSystemPrefersReducedMotion() {
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}

function readStoredPreference(): boolean | null {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored === "true") return true;
  if (stored === "false") return false;
  return null;
}

function applyReduceMotionPreference(enabled: boolean, followsSystem: boolean) {
  document.documentElement.classList.toggle("reduce-motion", enabled);
  document.documentElement.classList.toggle(
    "allow-motion",
    !followsSystem && !enabled
  );
}

export function useReducedMotion() {
  const [reduceMotion, setReduceMotionState] = useState(() => {
    const stored = readStoredPreference();
    if (stored !== null) return stored;
    return getSystemPrefersReducedMotion();
  });

  const [followsSystem, setFollowsSystem] = useState(
    () => readStoredPreference() === null
  );

  useEffect(() => {
    applyReduceMotionPreference(reduceMotion, followsSystem);
  }, [reduceMotion, followsSystem]);

  useEffect(() => {
    if (!followsSystem) return;

    const media = window.matchMedia("(prefers-reduced-motion: reduce)");
    const onChange = () => setReduceMotionState(media.matches);
    onChange();
    media.addEventListener("change", onChange);
    return () => media.removeEventListener("change", onChange);
  }, [followsSystem]);

  const setReduceMotion = useCallback((enabled: boolean, options?: { system?: boolean }) => {
    if (options?.system) {
      localStorage.removeItem(STORAGE_KEY);
      setFollowsSystem(true);
      setReduceMotionState(getSystemPrefersReducedMotion());
      return;
    }

    localStorage.setItem(STORAGE_KEY, enabled ? "true" : "false");
    setFollowsSystem(false);
    setReduceMotionState(enabled);
  }, []);

  return { reduceMotion, followsSystem, setReduceMotion };
}

/** Applies stored / system reduce-motion before React hydrates */
export function initReducedMotion() {
  const stored = readStoredPreference();
  const followsSystem = stored === null;
  const enabled = stored ?? getSystemPrefersReducedMotion();
  applyReduceMotionPreference(enabled, followsSystem);
}

import { useState, useEffect, useCallback } from 'react';

interface UseSpeechToTextReturn {
  isListening: boolean;
  transcript: string;
  startListening: () => void;
  stopListening: () => void;
  resetTranscript: () => void;
  isSupported: boolean;
}

export function useSpeechToText(): UseSpeechToTextReturn {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [isSupported, setIsSupported] = useState(false);

  useEffect(() => {
    if (typeof window !== 'undefined' && 'webkitSpeechRecognition' in window) {
      setIsSupported(true);
    } else if (typeof window !== 'undefined' && 'SpeechRecognition' in window) {
      setIsSupported(true);
    }
  }, []);

  const startListening = useCallback(() => {
    if (!isSupported) return;

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onstart = () => {
      setIsListening(true);
    };

    recognition.onresult = (event: any) => {
      let interimTranscript = '';
      let finalTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const transcript = event.results[i][0].transcript;
        if (event.results[i].isFinal) {
          finalTranscript += transcript + ' ';
        } else {
          interimTranscript += transcript;
        }
      }

      setTranscript(finalTranscript + interimTranscript);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListening(false);
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.start();

    return () => {
      recognition.stop();
    };
  }, [isSupported]);

  const stopListening = useCallback(() => {
    setIsListening(false);
  }, []);

  const resetTranscript = useCallback(() => {
    setTranscript('');
  }, []);

  return {
    isListening,
    transcript,
    startListening,
    stopListening,
    resetTranscript,
    isSupported,
  };
}

import { useRef, useState, useCallback, useEffect } from "react";

export interface UseSpeechReturn {
  isListening: boolean;
  isSupported: boolean;
  interimTranscript: string;
  error: string | null;
  startListening: () => void;
  stopListening: () => void;
  resetError: () => void;
}

type SpeechRecognitionInstance = {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  maxAlternatives: number;
  start: () => void;
  stop: () => void;
  abort: () => void;
  onstart: (() => void) | null;
  onend: (() => void) | null;
  onerror: ((e: { error: string }) => void) | null;
  onresult: ((e: SpeechRecognitionEvent) => void) | null;
};

type SpeechRecognitionEvent = {
  resultIndex: number;
  results: {
    length: number;
    [index: number]: {
      isFinal: boolean;
      0: { transcript: string };
    };
  };
};

function getSpeechRecognitionCtor(): (new () => SpeechRecognitionInstance) | null {
  if (typeof window === "undefined") return null;
  return (
    (window as Window & { SpeechRecognition?: new () => SpeechRecognitionInstance }).SpeechRecognition ??
    (window as Window & { webkitSpeechRecognition?: new () => SpeechRecognitionInstance }).webkitSpeechRecognition ??
    null
  );
}

export function useSpeech(onFinalTranscript: (text: string) => void): UseSpeechReturn {
  const recognitionRef = useRef(null);
  const onFinalRef = useRef(onFinalTranscript);
  const restartTimerRef = useRef<ReturnType | null>(null);
  const isListeningRef = useRef(false);

  const [isListening, setIsListening] = useState(false);
  const [isSupported] = useState(() => getSpeechRecognitionCtor() !== null);
  const [interimTranscript, setInterimTranscript] = useState("");
  const [error, setError] = useState(null);

  // Keep callback ref up to date
  useEffect(() => { onFinalRef.current = onFinalTranscript; }, [onFinalTranscript]);

  const createRecognition = useCallback(() => {
    const Ctor = getSpeechRecognitionCtor();
    if (!Ctor) return null;

    const rec = new Ctor();
    rec.continuous = true;
    rec.interimResults = true;
    rec.lang = "en-US";
    rec.maxAlternatives = 1;

    rec.onstart = () => {
      setIsListening(true);
      setError(null);
    };

    rec.onresult = (event: SpeechRecognitionEvent) => {
      let interim = "";
      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i];
        const text = result[0].transcript;
        if (result.isFinal) {
          const trimmed = text.trim();
          if (trimmed) onFinalRef.current(trimmed + " ");
        } else {
          interim += text;
        }
      }
      setInterimTranscript(interim);
    };

    rec.onerror = (e: { error: string }) => {
      // "no-speech" is common (silence timeout) — auto-restart if still listening
      if (e.error === "no-speech" && isListeningRef.current) {
        restartTimerRef.current = setTimeout(() => {
          try { recognitionRef.current?.start(); } catch {}
        }, 200);
        return;
      }
      if (e.error === "aborted") return; // intentional stop
      const messages: Record = {
        "not-allowed": "Microphone access denied — enable it in browser settings.",
        "audio-capture": "No microphone found.",
        "network": "Network error during speech recognition.",
      };
      setError(messages[e.error] ?? `Speech error: ${e.error}`);
      setIsListening(false);
      isListeningRef.current = false;
    };

    rec.onend = () => {
      setInterimTranscript("");
      // Auto-restart if we haven't intentionally stopped
      if (isListeningRef.current) {
        restartTimerRef.current = setTimeout(() => {
          try { recognitionRef.current?.start(); } catch {}
        }, 100);
      } else {
        setIsListening(false);
      }
    };

    return rec;
  }, []);

  const startListening = useCallback(() => {
    if (!isSupported) return;
    setError(null);
    isListeningRef.current = true;

    if (!recognitionRef.current) {
      recognitionRef.current = createRecognition();
    }
    try {
      recognitionRef.current?.start();
    } catch {
      // Already started — ignore
    }
    setIsListening(true);
  }, [isSupported, createRecognition]);

  const stopListening = useCallback(() => {
    isListeningRef.current = false;
    if (restartTimerRef.current) clearTimeout(restartTimerRef.current);
    recognitionRef.current?.stop();
    recognitionRef.current = null;
    setIsListening(false);
    setInterimTranscript("");
  }, []);

  const resetError = useCallback(() => setError(null), []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      isListeningRef.current = false;
      if (restartTimerRef.current) clearTimeout(restartTimerRef.current);
      try { recognitionRef.current?.abort(); } catch {}
    };
  }, []);

  return {
    isListening,
    isSupported,
    interimTranscript,
    error,
    startListening,
    stopListening,
    resetError,
  };
}

import { useCallback, useEffect } from "react";
import { useTheme as useNextTheme } from "next-themes";

export type AppTheme = "dark" | "light" | "system";

const THEME_CYCLE: AppTheme[] = ["light", "dark", "system"];

export { useTheme } from "next-themes";
export { ThemeProvider } from "@/components/theme-provider";

export function useAppTheme() {
  const { theme, setTheme, resolvedTheme, systemTheme } = useNextTheme();

  const appTheme = (theme ?? "system") as AppTheme;

  const cycleTheme = useCallback(() => {
    const index = THEME_CYCLE.indexOf(appTheme);
    const next = THEME_CYCLE[(index + 1) % THEME_CYCLE.length];
    setTheme(next);
  }, [appTheme, setTheme]);

  const setAppTheme = useCallback(
    (value: AppTheme) => {
      setTheme(value);
    },
    [setTheme]
  );

  return {
    theme: appTheme,
    setTheme: setAppTheme,
    resolvedTheme: resolvedTheme as "dark" | "light" | undefined,
    systemTheme: systemTheme as "dark" | "light" | undefined,
    cycleTheme,
  };
}

/** Cycles light → dark → system with Ctrl+Shift+L */
export function useThemeKeyboardShortcut(enabled = true) {
  const { cycleTheme } = useAppTheme();

  useEffect(() => {
    if (!enabled) return;

    const onKeyDown = (event: KeyboardEvent) => {
      if (
        event.defaultPrevented ||
        event.repeat ||
        !(event.ctrlKey || event.metaKey) ||
        !event.shiftKey
      ) {
        return;
      }

      if (event.key.toLowerCase() !== "l") return;

      const target = event.target;
      if (
        target instanceof HTMLElement &&
        (target.isContentEditable ||
          target.closest("input, textarea, select, [contenteditable='true']"))
      ) {
        return;
      }

      event.preventDefault();
      cycleTheme();
    };

    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [cycleTheme, enabled]);
}

import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

import { useRef, useState, useCallback, useEffect } from "react";

export interface VideoMetrics {
  facePresentPct: number;
  eyeContactPct: number;
  lookAwayCount: number;
  totalLookAwayMs: number;
  durationMs: number;
}

const DETECTION_INTERVAL_MS = 700;
const LOOK_AWAY_THRESHOLD_MS = 1500;

export function useWebcam() {
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const detectorRef = useRef<{ detect: (src: HTMLVideoElement) => Promise<Array<{ boundingBox: DOMRectReadOnly }>> } | null>(null);
  const intervalRef = useRef<ReturnType | null>(null);

  const [isActive, setIsActive] = useState(false);
  const [permissionDenied, setPermissionDenied] = useState(false);
  const [permissionRequested, setPermissionRequested] = useState(false);
  const [faceDetected, setFaceDetected] = useState(false);
  const [eyeContact, setEyeContact] = useState(false);
  const [hasFaceDetector, setHasFaceDetector] = useState(false);

  const metricsRef = useRef({
    startTime: 0,
    facePresentFrames: 0,
    eyeContactFrames: 0,
    totalFrames: 0,
    lookAwayCount: 0,
    totalLookAwayMs: 0,
    lastFaceSeenAt: Date.now(),
    inLookAway: false,
    lookAwayStartedAt: 0,
  });

  const getMetrics = useCallback((): VideoMetrics => {
    const m = metricsRef.current;
    const durationMs = m.startTime ? Date.now() - m.startTime : 0;
    return {
      facePresentPct: m.totalFrames > 0 ? Math.round((m.facePresentFrames / m.totalFrames) * 100) : 0,
      eyeContactPct: m.totalFrames > 0 ? Math.round((m.eyeContactFrames / m.totalFrames) * 100) : 0,
      lookAwayCount: m.lookAwayCount,
      totalLookAwayMs: m.totalLookAwayMs,
      durationMs,
    };
  }, []);

  const start = useCallback(async () => {
    setPermissionRequested(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "user", width: { ideal: 640 }, height: { ideal: 480 } },
        audio: false,
      });
      streamRef.current = stream;

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.muted = true;
        await videoRef.current.play().catch(() => {});
      }

      // Try to initialise FaceDetector (Chrome 70+)
      const FaceDetectorCtor = (window as Window & { FaceDetector?: new (opts?: object) => { detect: (src: HTMLVideoElement) => Promise<Array<{ boundingBox: DOMRectReadOnly }>> } }).FaceDetector;
      if (FaceDetectorCtor) {
        try {
          detectorRef.current = new FaceDetectorCtor({ maxDetectedFaces: 1, fastMode: true });
          setHasFaceDetector(true);
        } catch {
          detectorRef.current = null;
        }
      }

      const now = Date.now();
      metricsRef.current = {
        startTime: now,
        facePresentFrames: 0,
        eyeContactFrames: 0,
        totalFrames: 0,
        lookAwayCount: 0,
        totalLookAwayMs: 0,
        lastFaceSeenAt: now,
        inLookAway: false,
        lookAwayStartedAt: 0,
      };

      setIsActive(true);
      setPermissionDenied(false);
    } catch (err) {
      const name = (err as DOMException).name;
      if (name === "NotAllowedError" || name === "PermissionDeniedError") {
        setPermissionDenied(true);
      }
    }
  }, []);

  // Face detection loop — runs while isActive
  useEffect(() => {
    if (!isActive) return;

    const detect = async () => {
      const video = videoRef.current;
      const m = metricsRef.current;

      if (!video || video.readyState < 2 || video.paused) return;

      m.totalFrames++;

      let detected = false;
      let centered = false;

      if (detectorRef.current) {
        try {
          const faces = await detectorRef.current.detect(video);
          if (faces.length > 0) {
            detected = true;
            const box = faces[0].boundingBox;
            const vw = video.videoWidth || 640;
            const vh = video.videoHeight || 480;
            const faceArea = (box.width * box.height) / (vw * vh);
            const centerX = box.x + box.width / 2;
            centered = centerX > vw * 0.2 && centerX < vw * 0.8 && faceArea > 0.03;
          }
        } catch {
          // Detector failed — treat as active
          detected = true;
          centered = true;
        }
      } else {
        // No FaceDetector API — assume camera presence counts
        detected = true;
        centered = true;
      }

      if (detected) {
        m.facePresentFrames++;
        if (centered) m.eyeContactFrames++;

        if (m.inLookAway) {
          m.totalLookAwayMs += Date.now() - m.lookAwayStartedAt;
          m.inLookAway = false;
        }
        m.lastFaceSeenAt = Date.now();
      } else {
        const away = Date.now() - m.lastFaceSeenAt;
        if (away > LOOK_AWAY_THRESHOLD_MS && !m.inLookAway) {
          m.inLookAway = true;
          m.lookAwayStartedAt = m.lastFaceSeenAt + LOOK_AWAY_THRESHOLD_MS;
          m.lookAwayCount++;
        }
      }

      setFaceDetected(detected);
      setEyeContact(centered);
    };

    intervalRef.current = setInterval(() => { void detect(); }, DETECTION_INTERVAL_MS);
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isActive]);

  const stop = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((t) => t.stop());
      streamRef.current = null;
    }
    if (videoRef.current) videoRef.current.srcObject = null;
    setIsActive(false);
    setFaceDetected(false);
    setEyeContact(false);
  }, []);

  // Cleanup on unmount
  useEffect(() => () => stop(), [stop]);

  return {
    videoRef,
    isActive,
    permissionDenied,
    permissionRequested,
    faceDetected,
    eyeContact,
    hasFaceDetector,
    getMetrics,
    start,
    stop,
  };
}

