                        <>
                           speech.isListening ? speech.stopListening() : speech.startListening()}
                            className={`flex items-center gap-2 rounded-full px-3 py-1.5 text-xs font-semibold transition-all ${
                              speech.isListening
                                ? "bg-red-500 text-white hover:bg-red-600"
                                : "bg-muted text-muted-foreground hover:bg-muted/80 border border-border"
                            }`}
                            data-testid="button-mic-toggle"
                          >
                            {speech.isListening ? (
                              <>


                                Stop recording
                              </>
                            ) : (
                              <>

                                Speak answer
                              </>
                            )}

                          {speech.isListening && (

                              Recording — speak clearly

                          )}
                          {!speech.isListening && !answerText && (

                              Or type your answer above

                          )}
                          {answerText && !speech.isListening && (
                             setAnswerText("")}
                            >
                              Clear

                          )}
                        </>
                      ) : (


                          Speech-to-text not available in this browser

                      )}


                    {/* Speech permission error */}
                    {speech.error && (



                          {speech.error}


                    )}

                )}



                 setCurrentQuestionIndex((p) => Math.max(0, p - 1))}
                  disabled={currentQuestionIndex === 0}
                >
                  Previous


                {!currentQuestion.isAnswered ? (

                    {submitAnswer.isPending && }
                    Submit Answer

                ) : (
                   {
                      if (currentQuestionIndex < questions.length - 1) {
                        setCurrentQuestionIndex((p) => p + 1);
                      } else {
                        handleComplete();
                      }
                    }}
                    disabled={completeInterview.isPending}
                    className="px-8"
                    data-testid="button-next"
                  >
                    {completeInterview.isPending && }
                    {currentQuestionIndex < questions.length - 1 ? (
                      <>Next Question </>
                    ) : (
                      <>Finish Interview </>
                    )}

                )}


          )}

          {/* Question nav dots */}
          {questions.length > 1 && (


              {questions.map((q, i) => (
                 setCurrentQuestionIndex(i)}
                  className={`w-7 h-7 rounded-full text-xs font-semibold transition-all ${
                    i === currentQuestionIndex
                      ? "bg-primary text-primary-foreground scale-110"
                      : q.isAnswered
                      ? "bg-emerald-500/80 text-white"
                      : "bg-muted text-muted-foreground hover:bg-muted/80"
                  }`}
                  data-testid={`button-question-nav-${i}`}
                >
                  {i + 1}

              ))}

          )}


        {/* ── Right: sticky camera panel ── */}




          {/* Progress summary card */}



Progress




                Answered
                {answeredCount} / {questions.length}





              Time elapsed
              {formatTime(elapsedSeconds)}

            {answeredCount > 0 && (


                Avg score

                  {Math.round(
                    questions.filter((q) => q.isAnswered && q.score != null).reduce((s, q) => s + (q.score ?? 0), 0) /
                    Math.max(1, questions.filter((q) => q.isAnswered).length)
                  )}/100


            )}




  );
}

